  <title>ISG BPA — Business Planning &amp; Analytics</title>
  <link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/@tabler/icons-webfont@3.19.0/dist/tabler-icons.min.css">
  <link href="https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@300;400;500;600;700;800&family=IBM+Plex+Mono:wght@400;500;600&display=swap" rel="stylesheet">
  <script src="https://cdnjs.cloudflare.com/ajax/libs/Chart.js/4.4.1/chart.umd.js"></script>
  <script src="https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js"></script>
  <style>
/* ═══════════════════════════════════════════════════════════
   TOKENS
   Teal accent (#0d9488) instead of generic blue.
   Near-black sidebar. Barely-blue ground. Shadow-only cards.
═══════════════════════════════════════════════════════════ */
:root {
  --bg:          #f1f4fa;
  --surface:     #ffffff;
  --surface-2:   #f7f9fd;
  --card:        #ffffff;
  --nav:         #0c1526;
  --nav-border:  rgba(255,255,255,0.06);
  --nav-hover:   rgba(255,255,255,0.05);
  --nav-active:  rgba(13,148,136,0.20);
  --border:      #e4e8f4;
  --border-hi:   #ccd3e8;
  --text:        #0c1526;
  --text-2:      #4a5578;
  --text-3:      #92a0bf;
  --nav-text:    #dde5f4;
  --nav-text-2:  #607090;
  /* Primary: teal — evokes precision/technology, far from generic blue */
  --accent:      #0d9488;
  --accent-2:    #0f766e;
  --accent-dim:  rgba(13,148,136,0.09);
  --accent-lite: #f0fdfa;
  /* Per-channel colors */
  --emerald:     #059669;
  --emerald-dim: rgba(5,150,105,0.09);
  --red:         #dc2626;
  --red-dim:     rgba(220,38,38,0.09);
  --amber:       #d97706;
  --amber-dim:   rgba(217,119,6,0.09);
  --violet:      #7c3aed;
  --violet-dim:  rgba(124,58,237,0.09);
  --sky:         #0369a1;
  --sky-dim:     rgba(3,105,161,0.09);
  --font-ui:     'Plus Jakarta Sans','Segoe UI',sans-serif;
  --font-data:   'IBM Plex Mono','Courier New',monospace;
  /* Layered shadows for physical card feel */
  --sh-sm:  0 1px 2px rgba(12,21,38,0.06), 0 4px 16px rgba(12,21,38,0.04);
  --sh-md:  0 2px 6px rgba(12,21,38,0.08), 0 12px 32px rgba(12,21,38,0.07);
  --sh-lg:  0 4px 12px rgba(12,21,38,0.10), 0 20px 48px rgba(12,21,38,0.09);
}

/* ── Reset ── */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
html, body { height: 100%; }
body { background: var(--bg); color: var(--text); font-family: var(--font-ui); font-size: 14px; line-height: 1.5; overflow: hidden; -webkit-font-smoothing: antialiased; }
#home-view      { display: flex; flex-direction: column; height: 100vh; overflow-y: auto; background: var(--bg); }
#dashboard-view { display: none; height: 100vh; flex-direction: column; }

/* ═══════════════════════════════════════════════════════════
   HOME — STATUS BAR (slim, dark)
═══════════════════════════════════════════════════════════ */
.home-bar {
  display: flex; align-items: center; gap: 10px;
  padding: 8px 48px;
  background: var(--nav);
  border-bottom: 1px solid var(--nav-border);
  font-size: 11px; color: rgba(255,255,255,0.35);
  letter-spacing: 0.06em; flex-shrink: 0;
}
.live-dot {
  width: 6px; height: 6px; border-radius: 50%;
  background: var(--accent); flex-shrink: 0;
  box-shadow: 0 0 0 0 rgba(13,148,136,0.5);
  animation: lp 2.4s ease-out infinite;
}
@keyframes lp {
  0%   { box-shadow: 0 0 0 0   rgba(13,148,136,0.5); }
  70%  { box-shadow: 0 0 0 8px rgba(13,148,136,0); }
  100% { box-shadow: 0 0 0 0   rgba(13,148,136,0); }
}
.bar-live  { color: var(--accent); font-weight: 700; }
.bar-sep   { color: rgba(255,255,255,0.15); }
.bar-push  { flex: 1; }

/* ═══════════════════════════════════════════════════════════
   HOME — HERO
   Dark, but text-first. The title is the hero.
   Live KPI strip at the bottom — that's the visual anchor.
═══════════════════════════════════════════════════════════ */
.home-hero {
  background: var(--nav);
  padding: 52px 48px 0;
  flex-shrink: 0;
  position: relative;
  overflow: hidden;
}
/* Subtle geometric lines — not a dot grid, more distinctive */
.home-hero::before {
  content: '';
  position: absolute; inset: 0;
  background:
    linear-gradient(rgba(13,148,136,0.06) 1px, transparent 1px),
    linear-gradient(90deg, rgba(13,148,136,0.06) 1px, transparent 1px);
  background-size: 64px 64px;
  pointer-events: none;
}
.home-hero::after {
  content: '';
  position: absolute; top: 0; right: 0;
  width: 520px; height: 380px;
  background: radial-gradient(ellipse at 70% 30%, rgba(13,148,136,0.12) 0%, transparent 65%);
  pointer-events: none;
}
.hero-body { position: relative; z-index: 1; }
.hero-eye {
  font-size: 10px; font-weight: 700; letter-spacing: 0.2em; text-transform: uppercase;
  color: var(--accent); margin-bottom: 18px;
  display: flex; align-items: center; gap: 10px;
}
.hero-eye::before { content: ''; width: 16px; height: 2px; background: var(--accent); flex-shrink: 0; }
.hero-title {
  font-size: clamp(3rem, 5.5vw, 4.4rem);
  font-weight: 800; line-height: 1.04; letter-spacing: -0.04em; color: #fff;
  margin-bottom: 2px;
}
.hero-title-b { color: rgba(255,255,255,0.28); font-weight: 300; }
.hero-sub { font-size: 14px; color: rgba(255,255,255,0.36); margin-bottom: 14px; }
.hero-desc { font-size: 12.5px; color: rgba(255,255,255,0.28); max-width: 480px; line-height: 1.7; }
.hero-logo { position: absolute; top: 0; right: 48px; z-index: 1; }

/* KPI strip — white panel rising from dark hero */
.hero-kpi-strip {
  position: relative; z-index: 1;
  display: flex; align-items: stretch;
  margin-top: 40px;
  background: var(--card);
  border-radius: 16px 16px 0 0;
  border: 1px solid rgba(255,255,255,0.12);
  border-bottom: none;
  box-shadow: 0 -8px 32px rgba(12,21,38,0.22), 0 -2px 8px rgba(12,21,38,0.14);
  overflow: hidden;
}
/* Teal accent strip at very top of the white panel */
.hero-kpi-strip::before {
  content: '';
  position: absolute; top: 0; left: 0; right: 0; height: 2px;
  background: linear-gradient(90deg, var(--accent), rgba(13,148,136,0.3), transparent);
}
.hk {
  flex: 1; padding: 22px 24px 18px;
  border-right: 1px solid var(--border);
  position: relative;
  transition: background 0.18s;
}
.hk:last-child { border-right: none; }
.hk:hover { background: #fafcfc; }
.hk-val {
  font-family: var(--font-data);
  font-size: 26px; font-weight: 600;
  color: var(--text); letter-spacing: -0.04em; line-height: 1;
  margin-bottom: 6px;
}
.hk-label {
  font-size: 10px; font-weight: 700; letter-spacing: 0.1em;
  text-transform: uppercase; color: var(--text-3);
  margin-bottom: 4px;
}
.hk-trend {
  font-size: 10px; font-weight: 700;
  display: flex; align-items: center; gap: 3px;
}

/* ═══════════════════════════════════════════════════════════
   HOME — MODULES
═══════════════════════════════════════════════════════════ */
.home-modules {
  background: var(--card);
  border-left: 1px solid var(--border);
  border-right: 1px solid var(--border);
  border-bottom: 1px solid var(--border);
  border-radius: 0 0 16px 16px;
  margin: 0 48px;
  padding: 28px 28px 36px;
  box-shadow: var(--sh-sm);
}
.modules-below {
  padding: 28px 48px 56px; background: var(--bg); flex: 1;
}
.sec-eyebrow {
  font-size: 10px; font-weight: 700; letter-spacing: 0.18em; text-transform: uppercase;
  color: var(--text-3); margin-bottom: 20px;
  display: flex; align-items: center; gap: 8px;
}
.sec-eyebrow::after {
  content: ''; flex: 1; height: 1px; background: var(--border); max-width: 120px;
}
.tiles-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
  gap: 16px;
}

/* ── TILE — big metric dominates, everything else supports it ── */
.tile {
  background: var(--card);
  border-radius: 16px;
  padding: 0;
  cursor: pointer; position: relative; overflow: hidden;
  box-shadow: var(--sh-sm);
  border: 1px solid var(--border);
  transition: box-shadow 0.22s, transform 0.22s, border-color 0.22s;
  text-decoration: none; display: flex; flex-direction: column; color: inherit;
}
.tile:hover {
  box-shadow: var(--sh-lg);
  transform: translateY(-4px);
  border-color: var(--border-hi);
}
/* Colored left rail — thin, always visible, encodes module identity */
.tile::before {
  content: '';
  position: absolute; top: 0; left: 0; bottom: 0; width: 3px;
  background: var(--tile-accent, var(--accent));
  border-radius: 16px 0 0 16px;
}
/* Metric area — top section, tinted subtly with the module color */
.tile-metric-area {
  padding: 24px 24px 16px 28px;
  background: linear-gradient(135deg, color-mix(in srgb, var(--tile-accent, var(--accent)) 5%, white), white);
  border-bottom: 1px solid var(--border);
}
.tile-metric {
  font-family: var(--font-data);
  font-size: 42px; font-weight: 600;
  letter-spacing: -0.05em; line-height: 1;
  color: var(--tile-accent, var(--accent));
  margin-bottom: 0;
}
.tile-head {
  display: flex; justify-content: space-between; align-items: center;
  margin-bottom: 10px;
}
.tile-icon {
  width: 34px; height: 34px; border-radius: 9px;
  background: color-mix(in srgb, var(--tile-accent, var(--accent)) 12%, white);
  display: flex; align-items: center; justify-content: center;
  font-size: 17px; color: var(--tile-accent, var(--accent));
  transition: background 0.22s, color 0.22s;
}
.tile:hover .tile-icon {
  background: var(--tile-accent, var(--accent)); color: #fff;
}
.tile-arrow { font-size: 15px; color: var(--text-3); transition: color 0.22s, transform 0.22s; }
.tile:hover .tile-arrow { color: var(--tile-accent, var(--accent)); transform: translate(2px,-2px); }
/* Body section */
.tile-body { padding: 18px 24px 20px 28px; flex: 1; display: flex; flex-direction: column; }
.tile-name {
  font-size: 15px; font-weight: 700; color: var(--text);
  margin-bottom: 6px; line-height: 1.25;
}
.tile-desc {
  font-size: 12px; color: var(--text-2); line-height: 1.65; flex: 1; margin-bottom: 16px;
}
.tile-footer {
  display: flex; align-items: center; gap: 6px;
  padding-top: 12px; border-top: 1px solid var(--border);
  font-size: 11px; color: var(--text-3); font-family: var(--font-data);
}
.tile-tag { font-weight: 600; color: var(--tile-accent, var(--accent)); }

/* ═══════════════════════════════════════════════════════════
   DASHBOARD — HEADER
═══════════════════════════════════════════════════════════ */
.dash-header {
  height: 52px; background: var(--surface); border-bottom: 1px solid var(--border);
  display: flex; align-items: center; justify-content: space-between;
  padding: 0 16px; flex-shrink: 0;
  box-shadow: 0 1px 0 var(--border); z-index: 10; gap: 12px;
}
.hdr-left  { display: flex; align-items: center; gap: 10px; min-width: 0; }
.hdr-right { display: flex; align-items: center; gap: 6px;  flex-shrink: 0; }
.hdr-brand { font-size: 13px; font-weight: 800; color: var(--text); letter-spacing: -0.02em; white-space: nowrap; }
.hdr-divider { width: 1px; height: 18px; background: var(--border); flex-shrink: 0; }
.breadcrumb { font-size: 12px; color: var(--text-2); display: flex; align-items: center; gap: 6px; }
.breadcrumb span { cursor: pointer; transition: color 0.15s; }
.breadcrumb span:hover { color: var(--accent); }
.breadcrumb .bsep { color: var(--border-hi); font-size: 15px; }
.hdr-stamp { font-size: 10px; color: var(--text-3); font-family: var(--font-data); }
.ctx-pill {
  display: inline-flex; align-items: center; gap: 5px;
  padding: 4px 10px; border-radius: 20px;
  background: var(--accent-dim); border: 1px solid rgba(13,148,136,0.18);
  font-size: 11px; font-weight: 600; color: var(--accent); white-space: nowrap;
}
.btn-icon {
  width: 32px; height: 32px; background: transparent;
  border: 1px solid transparent; color: var(--text-2);
  cursor: pointer; font-size: 16px; border-radius: 8px;
  display: flex; align-items: center; justify-content: center; transition: all 0.15s;
}
.btn-icon:hover { background: var(--surface-2); border-color: var(--border); color: var(--text); }
.btn-sm {
  background: var(--surface-2); border: 1px solid var(--border); color: var(--text-2);
  cursor: pointer; font-size: 11px; font-weight: 600; padding: 5px 12px; border-radius: 7px;
  display: inline-flex; align-items: center; gap: 5px; font-family: var(--font-ui); transition: all 0.15s;
}
.btn-sm:hover { border-color: var(--accent); color: var(--accent); }

/* ═══════════════════════════════════════════════════════════
   DASHBOARD — LAYOUT
═══════════════════════════════════════════════════════════ */
.dash-body { display: flex; flex: 1; overflow: hidden; }

/* ── LEFT NAV ── */
.left-panel {
  width: 234px; background: var(--nav); border-right: 1px solid var(--nav-border);
  flex-shrink: 0; display: flex; flex-direction: column;
  transition: width 0.24s ease; overflow: hidden;
}
.left-panel.collapsed { width: 0; border: none; }
.nav-head {
  padding: 18px 18px 14px; border-bottom: 1px solid var(--nav-border); flex-shrink: 0;
}
.nav-eyebrow { font-size: 9px; font-weight: 700; letter-spacing: 0.2em; text-transform: uppercase; color: var(--nav-text-2); margin-bottom: 4px; }
.nav-mod { font-size: 13px; font-weight: 700; color: var(--nav-text); white-space: nowrap; }
.nav-links { padding: 10px; flex: 1; overflow-y: auto; }
.nav-link {
  display: flex; align-items: center; gap: 9px; padding: 8px 10px;
  color: var(--nav-text-2); font-size: 12px; font-weight: 500;
  cursor: pointer; white-space: nowrap; border-radius: 8px;
  border-left: 2px solid transparent; transition: all 0.15s; margin-bottom: 2px;
}
.nav-link:hover { color: var(--nav-text); background: var(--nav-hover); }
.nav-link.active { color: #5eead4; background: var(--nav-active); border-left-color: var(--accent); font-weight: 600; }
.nav-link i { font-size: 14px; flex-shrink: 0; }
.nav-foot { padding: 12px 18px; border-top: 1px solid var(--nav-border); font-size: 10px; color: var(--nav-text-2); flex-shrink: 0; }

/* ── MAIN CONTENT ── */
.main-content { flex: 1; padding: 20px 24px; overflow-y: auto; background: var(--bg); display: flex; flex-direction: column; min-width: 0; }

/* ── FILTER CHIPS ── */
.filter-chips { display: flex; flex-wrap: wrap; gap: 6px; margin-bottom: 14px; }
.chip {
  display: inline-flex; align-items: center; gap: 5px;
  background: var(--accent-dim); border: 1px solid rgba(13,148,136,0.22);
  border-radius: 20px; padding: 3px 10px 3px 8px;
  font-size: 11px; font-weight: 600; color: var(--accent); cursor: pointer; transition: all 0.15s;
}
.chip:hover { background: var(--red-dim); border-color: rgba(220,38,38,0.28); color: var(--red); }

/* ── CHANNEL TABS — 6 tabs ── */
.channel-tabs { display: flex; margin-bottom: 20px; border-bottom: 2px solid var(--border); overflow-x: auto; }
.channel-tab {
  display: flex; align-items: center; gap: 7px;
  padding: 9px 16px; font-size: 12px; font-weight: 600;
  cursor: pointer; color: var(--text-3); white-space: nowrap;
  border-bottom: 2px solid transparent; margin-bottom: -2px; transition: all 0.15s;
}
.channel-tab:hover { color: var(--text-2); }
.channel-tab.active { color: var(--ctab-c, var(--accent)); border-bottom-color: var(--ctab-c, var(--accent)); }
.tab-pip { width: 6px; height: 6px; border-radius: 50%; background: var(--ctab-c, var(--accent)); opacity: 0.5; flex-shrink: 0; transition: opacity 0.15s; }
.channel-tab.active .tab-pip { opacity: 1; }

/* ── SECTIONS ── */
.module-section { display: none; }
.module-section.active { display: block; }
.page-section { display: none; }
.page-section.active { display: block; animation: fade-in 0.18s ease; }
@keyframes fade-in { from { opacity: 0; transform: translateY(5px); } to { opacity: 1; transform: none; } }

/* ═══════════════════════════════════════════════════════════
   KPI CARDS
   No borders, no icons, no colored accent bars.
   Shadow is the only thing defining the card shape.
   The number is the whole design.
═══════════════════════════════════════════════════════════ */
.kpi-row { display: grid; grid-template-columns: repeat(auto-fit, minmax(180px, 1fr)); gap: 14px; margin-bottom: 20px; }
.kpi-card {
  background: var(--card); border-radius: 14px; padding: 20px 20px 16px;
  box-shadow: var(--sh-sm); border: 1px solid var(--border);
  position: relative; overflow: hidden;
  transition: box-shadow 0.2s, transform 0.18s;
}
/* Hairline accent at top — drawn from the KPI value color via inline style */
.kpi-card::after {
  content: '';
  position: absolute; top: 0; left: 0; right: 0; height: 2px;
  background: linear-gradient(90deg, var(--kpi-accent, var(--border-hi)), transparent 70%);
}
.kpi-card:hover { box-shadow: var(--sh-md); transform: translateY(-2px); }
.kpi-label {
  display: block; font-size: 10px; font-weight: 700; letter-spacing: 0.1em;
  text-transform: uppercase; color: var(--text-3); margin-bottom: 12px;
}
.kpi-value {
  font-family: var(--font-data); font-size: 36px; font-weight: 600;
  letter-spacing: -0.04em; color: var(--text); line-height: 1; margin-bottom: 9px;
}
.kpi-sub { font-size: 11px; font-weight: 600; color: var(--text-2); display: flex; align-items: center; gap: 4px; }

/* ═══════════════════════════════════════════════════════════
   VISUAL CARDS
═══════════════════════════════════════════════════════════ */
.visual-row { display: grid; grid-template-columns: repeat(auto-fit, minmax(360px, 1fr)); gap: 14px; margin-bottom: 20px; }
.visual-card {
  background: var(--card); border-radius: 14px; padding: 18px 20px;
  min-height: 280px; display: flex; flex-direction: column;
  box-shadow: var(--sh-sm); border: 1px solid var(--border); transition: box-shadow 0.2s, border-color 0.2s;
}
.visual-card:hover { box-shadow: var(--sh-md); border-color: var(--border-hi); }
.vc-head {
  margin-bottom: 14px; padding-bottom: 14px; border-bottom: 1px solid var(--border);
  display: flex; justify-content: space-between; align-items: flex-start; gap: 12px;
}
.vc-titles { flex: 1; min-width: 0; }
.vc-title { font-size: 13px; font-weight: 700; color: var(--text); margin-bottom: 3px; line-height: 1.3; }
.vc-sub   { font-size: 11px; color: var(--text-3); font-weight: 500; letter-spacing: 0.01em; }
.chart-toggle { display: flex; gap: 4px; flex-shrink: 0; }
.ctbtn {
  background: transparent; border: 1px solid var(--border); color: var(--text-2);
  font-size: 10px; font-weight: 600; padding: 3px 9px; border-radius: 5px;
  cursor: pointer; font-family: var(--font-ui); transition: all 0.15s;
}
.ctbtn:hover { border-color: var(--accent); color: var(--accent); }
.ctbtn.on { background: var(--accent-dim); border-color: var(--accent); color: var(--accent); }

/* ═══════════════════════════════════════════════════════════
   TABLES
═══════════════════════════════════════════════════════════ */
.tw { overflow: auto; flex: 1; }
table.dt { width: 100%; border-collapse: collapse; font-size: 12px; }
.dt th {
  background: var(--surface-2); color: var(--text-2); padding: 9px 12px; text-align: left;
  border-bottom: 1px solid var(--border); white-space: nowrap;
  position: sticky; top: 0; z-index: 1; cursor: pointer; user-select: none;
  font-size: 10px; font-weight: 700; letter-spacing: 0.07em; text-transform: uppercase; transition: color 0.15s;
}
.dt th:hover { color: var(--text); }
.dt th .si { margin-left: 4px; opacity: 0.4; font-size: 9px; }
.dt th.sa .si::before { content:'▲'; opacity:1; }
.dt th.sd .si::before { content:'▼'; opacity:1; }
.dt td { padding: 9px 12px; border-bottom: 1px solid var(--border); white-space: nowrap; color: var(--text); }
.dt tr:nth-child(even) td { background: #f9fbff; }
.dt tr:hover td { background: var(--accent-lite); }
.dt .rn { color: var(--text-3); font-family: var(--font-data); font-size: 10px; text-align: right; }
.stick { position: sticky; left: 0; background: var(--card); z-index: 1; }
.dt tr:hover .stick { background: var(--accent-lite); }
.tbar { display: flex; align-items: center; gap: 10px; margin-bottom: 14px; flex-wrap: wrap; }
.tsearch {
  padding: 8px 14px; background: var(--surface-2); border: 1px solid var(--border);
  border-radius: 8px; color: var(--text); font-size: 12px; font-family: var(--font-ui);
  outline: none; min-width: 240px; transition: border-color 0.15s;
}
.tsearch:focus { border-color: var(--accent); background: var(--surface); }
.tsearch::placeholder { color: var(--text-3); }
.rct { font-size: 11px; color: var(--text-2); margin-left: auto; font-family: var(--font-data); }
.xbtns { display: flex; gap: 6px; }
.xbtn {
  display: flex; align-items: center; gap: 5px; padding: 7px 13px; border-radius: 7px;
  font-size: 11px; font-weight: 700; cursor: pointer; border: 1px solid;
  font-family: var(--font-ui); transition: all 0.15s;
}
.xbtn.csv  { background: var(--emerald-dim); color: var(--emerald); border-color: rgba(5,150,105,0.22); }
.xbtn.csv:hover  { background: var(--emerald); color: #fff; }
.xbtn.xlsx { background: var(--accent-dim);   color: var(--accent);  border-color: rgba(13,148,136,0.22); }
.xbtn.xlsx:hover { background: var(--accent); color: #fff; }

/* ═══════════════════════════════════════════════════════════
   RIGHT FILTER PANEL
═══════════════════════════════════════════════════════════ */
.right-panel {
  width: 260px; background: var(--surface); border-left: 1px solid var(--border);
  flex-shrink: 0; display: flex; flex-direction: column;
  transition: width 0.24s ease; overflow: hidden;
}
.right-panel.collapsed { width: 0; border: none; }
.fp-head {
  padding: 14px 16px; border-bottom: 1px solid var(--border);
  font-weight: 700; font-size: 10px; letter-spacing: 0.14em; text-transform: uppercase;
  color: var(--text-2); display: flex; justify-content: space-between; align-items: center; flex-shrink: 0;
}
.fp-search { padding: 10px 12px; flex-shrink: 0; }
.fp-si {
  width: 100%; padding: 7px 12px; background: var(--surface-2); border: 1px solid var(--border);
  border-radius: 8px; color: var(--text); font-family: var(--font-ui); outline: none; font-size: 12px; transition: border-color 0.15s;
}
.fp-si:focus { border-color: var(--accent); }
.fp-list { overflow-y: auto; flex: 1; padding: 4px 12px 8px; }
.fp-foot { padding: 10px 12px; border-top: 1px solid var(--border); flex-shrink: 0; }
.reset-btn {
  width: 100%; padding: 9px; background: var(--red-dim); border: 1px solid rgba(220,38,38,0.22);
  border-radius: 8px; color: var(--red); cursor: pointer; font-size: 11px; font-weight: 700;
  font-family: var(--font-ui); display: flex; align-items: center; justify-content: center; gap: 6px; transition: all 0.15s;
}
.reset-btn:hover { background: var(--red); color: #fff; }
.fd { margin-bottom: 8px; }
.fd-btn {
  width: 100%; text-align: left; background: transparent; border: 1px solid var(--border);
  padding: 8px 10px; border-radius: 8px; color: var(--text); cursor: pointer;
  display: flex; justify-content: space-between; align-items: center;
  font-size: 11px; font-weight: 700; font-family: var(--font-ui); transition: border-color 0.15s;
}
.fd-btn:hover { border-color: var(--accent); }
.fd-body {
  display: none; border: 1px solid var(--border); border-top: none;
  background: var(--surface-2); padding: 8px; border-radius: 0 0 8px 8px; max-height: 148px; overflow-y: auto;
}
.fd-body.open { display: block; }
.fchk { display: flex; align-items: center; gap: 8px; font-size: 12px; margin-bottom: 5px; cursor: pointer; color: var(--text-2); transition: color 0.15s; }
.fchk:hover { color: var(--text); }
.fchk input { cursor: pointer; accent-color: var(--accent); }
.is { width: 100%; padding: 5px 8px; font-size: 11px; margin-bottom: 6px; background: var(--surface); border: 1px solid var(--border); color: var(--text); border-radius: 5px; outline: none; font-family: var(--font-ui); }
hr.rule { border: none; border-top: 1px solid var(--border); margin: 5px 0; }

/* ── BADGES ── */
.badge { display: inline-flex; align-items: center; padding: 2px 9px; border-radius: 20px; font-size: 10px; font-weight: 700; letter-spacing: 0.04em; }
.b-hi  { background: var(--red-dim);    color: var(--red); }
.b-ok  { background: var(--emerald-dim);color: var(--emerald); }
.b-md  { background: var(--amber-dim);  color: var(--amber); }
.b-acc { background: var(--accent-dim); color: var(--accent); }

/* ── SEVERITY ── */
.sev-row { display: flex; gap: 6px; margin-bottom: 14px; }
.sev-btn { padding: 4px 13px; border-radius: 20px; font-size: 11px; font-weight: 700; cursor: pointer; border: 1px solid; font-family: var(--font-ui); transition: all 0.15s; }
.sev-btn.all     { border-color: var(--border);                  color: var(--text-2); background: transparent; }
.sev-btn.all.on  { background: var(--surface-2); border-color: var(--border-hi); color: var(--text); }
.sev-btn.hi      { border-color: rgba(220,38,38,0.3); color: var(--red);    background: var(--red-dim); }
.sev-btn.hi.on   { background: var(--red);    color: #fff; }
.sev-btn.med     { border-color: rgba(217,119,6,0.3); color: var(--amber);  background: var(--amber-dim); }
.sev-btn.med.on  { background: var(--amber);  color: #fff; }
.sev-btn.lo      { border-color: rgba(5,150,105,0.3); color: var(--emerald);background: var(--emerald-dim); }
.sev-btn.lo.on   { background: var(--emerald);color: #fff; }

/* ── SCROLLBARS ── */
::-webkit-scrollbar { width: 5px; height: 5px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: var(--border); border-radius: 3px; }
::-webkit-scrollbar-thumb:hover { background: var(--border-hi); }
  </style>
</head>
