const REGIONS=['AMER','AMER','EMEA','APJ'];
const SUBREGS={AMER:['North America','LATAM'],EMEA:['Western Europe','Eastern Europe'],APJ:['SEA','ANZ','Japan']};
const PARTNERS=['Dell','OSP'], LOCS=['New York Hub','London HQ','Tokyo Base','Austin DC','Sydney Office','Paris HQ'];
const QUEUES=['Queue_Alpha','Queue_Beta','Queue_Delta'], BRS=['BR_Direct','BR_Indirect'], LOBS=['ISG','ESG','HES'];
function ri(a,b){return Math.floor(Math.random()*(b-a+1))+a;}
function rf(arr){return arr[Math.floor(Math.random()*arr.length)];}
function rfn(a,b,d=1){return parseFloat((Math.random()*(b-a)+a).toFixed(d));}

let rawData=[];
function generateRawData(){
  rawData=[];
  for(let i=0;i<150;i++){
    const reg=rf(REGIONS), sub=rf(SUBREGS[reg]), par=rf(PARTNERS), loc=rf(LOCS), q=rf(QUEUES), br=rf(BRS);
    const r2=Math.random(), fy=r2>.55?'FY26':r2>.25?'FY27':'FY25';
    const qtr=rf(['Q1','Q2','Q3','Q4']), mon=rf(['M1','M2','M3','M4','M5','M6']);
    const wn=ri(1,52), w=`W${wn}`;
    const sr=ri(1000,8000),fasu=ri(2000,12000),tasu=ri(500,6000),fdsr=ri(1000,9000);
    const lob=rf(LOBS), status=Math.abs(sr-fdsr)/fdsr<0.1?'Within Tolerance':'Out of Bounds';
    rawData.push({i:i+1,region:reg,subregion:sub,partner:par,location:loc,queue:q,br,fy,quarter:qtr,month:mon,week:w,weekNum:wn,sr,fasu,tasu,fdsr,lob,status});
  }
}
