/* ─ TREND DATA ─ */
const Q_WEEKS={Q1:Array.from({length:13},(_,i)=>i+1),Q2:Array.from({length:13},(_,i)=>i+14),Q3:Array.from({length:13},(_,i)=>i+27),Q4:Array.from({length:13},(_,i)=>i+40)};
const M_WEEKS={M1:[1,2,3,4],M2:[5,6,7,8],M3:[9,10,11,12,13],M4:[14,15,16,17],M5:[18,19,20,21,22],M6:[23,24,25,26]};
