function _t(base,amp,ph){return Array.from({length:52},(_,i)=>Math.max(10,Math.round(base+amp*Math.sin(2*Math.PI*(i+(ph||0))/13))));}
// All T52 values are weekly. fa-asu: 28.3K/wk (1.47M÷52). dp-ov-*: ~11.3K/wk (587K÷52).
// Care/FS sub-channels are shares of weekly SR/dispatch totals.
const T52={
  'fa-asu': _t(28300,2800,0),'fa-wo': _t(7900,1100,0),
  'dp-ov-fs':  _t(5900,620,0),'dp-ov-care': _t(4600,480,2),'dp-ov-ms': _t(2400,260,4),
