/* ─ FILTER HELPERS ─ */
function getActiveFilters(){
  const gs={};
  document.querySelectorAll('#filter-container input[type=checkbox]').forEach(cb=>{
    const g=cb.dataset.group; if(!g) return;
    if(!gs[g]) gs[g]={a:false,v:[]};
    if(cb.value==='All'){if(cb.checked) gs[g].a=true;} else if(cb.checked) gs[g].v.push(cb.value);
  });
  const r={};
  Object.entries(gs).forEach(([g,s])=>{if(!s.a) r[g]=s.v;});
  return r;
}
function getFYMult(){const f=getActiveFilters().fy;if(!f) return(FY_SCALE.FY26+FY_SCALE.FY27)/2;if(!f.length) return 0;return f.reduce((s,x)=>s+(FY_SCALE[x]||1),0)/f.length;}
function getWeekIdx(){
  const a=getActiveFilters(); let idx=Array.from({length:52},(_,i)=>i);
  if(a.quarter!==undefined){if(!a.quarter.length) return[];const qn=a.quarter.flatMap(q=>Q_WEEKS[q]||[]);idx=idx.filter(i=>qn.includes(i+1));}
  if(a.month!==undefined){if(!a.month.length) return[];const mn=a.month.flatMap(m=>M_WEEKS[m]||[]);if(mn.length) idx=idx.filter(i=>mn.includes(i+1));}
  if(a.week!==undefined){if(!a.week.length) return[];const wn=a.week.map(w=>parseInt(w.slice(1)));idx=idx.filter(i=>wn.includes(i+1));}
  return idx;
}
function getMonIdx(){
  const a=getActiveFilters(); let idx=Array.from({length:12},(_,i)=>i);
  if(a.quarter!==undefined){if(!a.quarter.length) return[];const qi=a.quarter.flatMap(q=>Q_MI[q]||[]);idx=idx.filter(i=>qi.includes(i));}
  if(a.month!==undefined){if(!a.month.length) return[];const mi=a.month.map(m=>M_LI[m]).filter(i=>i!==undefined);if(mi.length) idx=idx.filter(i=>mi.includes(i));}
  return idx;
}
function hideAll(){
  const a=getActiveFilters();
  if(getFYMult()===0) return true;
  if(a.quarter!==undefined&&!a.quarter.length) return true;
  if(a.month!==undefined&&!a.month.length) return true;
  if(a.region!==undefined&&!a.region.length) return true;
  return false;
}
function selQ(){const a=getActiveFilters(),allQ=['Q1','Q2','Q3','Q4'];return a.quarter===undefined?allQ:allQ.filter(q=>a.quarter.includes(q));}

