function updateChips(){
  const row=document.getElementById('filter-chips-row'); row.innerHTML='';
  const active=getActiveFilters();
  Object.entries(active).forEach(([g,vals])=>vals.forEach(v=>{
    const c=document.createElement('div'); c.className='chip';
    c.innerHTML=`<i class="ti ti-x" style="font-size:9px;"></i> ${g}: ${v}`;
    c.onclick=()=>{const cb=document.querySelector(`#filter-container input[data-group="${g}"][value="${v}"]`);if(cb){cb.checked=false;onFilterChange();}};
    row.appendChild(c);
  }));
  const fyc=[...document.querySelectorAll('input[data-group="fy"]:checked')].map(c=>c.value);
  const rc=[...document.querySelectorAll('input[data-group="region"]:checked')].map(c=>c.value);
  document.getElementById('global-context').innerText=`${fyc.length?fyc.join(', '):'All FY'} · ${rc.length?rc.join(', '):'All Regions'}`;
}
