/* ─ TRIGGER UPDATE ─ */
const FAC=new Set(['fa-chart-hbar','fa-chart-partner','dp-chart-overall-region','dp-chart-overall-qoq','dp-chart-overall-mom','dp-chart-overall-wow','ap-asu-trend','ap-new-contracts','ap-apos-renewal','ap-decline','ap-dsp-trend','ap-dsp-region','ap-sr-trend','ap-sr-region','ap-fs-trend','ap-fs-overall','ap-care-trend','ap-care-region','ap-care-sub']);
function triggerUpdate(){
  document.querySelectorAll('.kpi-dynamic:not(#dr-total-records):not(#da-total)').forEach(el=>{
    let t=el.innerText.trim(); if(t.startsWith('+')||t.startsWith('-')) return;
    let isP=t.includes('%'),isK=t.includes('K'),isM=t.endsWith('M');
    let n=parseFloat(t.replace(/[^0-9.]/g,''));
    if(isNaN(n)||n===0) return;
    let v=n*(1+(Math.random()*0.1-0.05));
    if(isP) el.innerText=Math.max(0,Math.min(99.9,v)).toFixed(1)+'%';
    else if(isM) el.innerText=v.toFixed(2)+'M';
    else if(isK) el.innerText=v.toFixed(1)+'K';
    else el.innerText=Math.round(Math.max(0,v)).toLocaleString('en-IN');
  });
  if(activeModule==='data-raw') renderRawTable();
  if(activeModule==='demand-alerts') renderAlerts(curSev);
  if(activeModule==='forecast-accuracy'){genActualsTable();genPartnerTable();}
  Object.entries(CI).forEach(([id,c])=>{if(!c||FAC.has(id)) return;c.data.datasets.forEach(ds=>{ds.data=ds.data.map(v=>Math.max(10,v*(1+(Math.random()*0.3-0.15))));});c.update();});
  applyAll();
}

