/* ─ RAW TABLE ─ */
let rSortCol=null,rSortDir=1,fRaw=[...rawData];
function getFilteredRaw(){
  const a=getActiveFilters(),s=(document.getElementById('raw-search')?.value||'').toLowerCase();
  return rawData.filter(r=>{
    if(a.region&&!a.region.includes(r.region)) return false;
    if(a.subregion&&!a.subregion.includes(r.subregion)) return false;
    if(a.lob&&!a.lob.includes(r.lob)) return false;
    if(a.location&&!a.location.includes(r.location)) return false;
    if(a.queue&&!a.queue.includes(r.queue)&&!a.queue.includes(r.br)) return false;
    if(a.fy&&!a.fy.includes(r.fy)) return false;
    if(a.quarter&&!a.quarter.includes(r.quarter)) return false;
    if(a.month&&!a.month.includes(r.month)) return false;
    if(a.week&&!a.week.includes(r.week)) return false;
    if(s&&!Object.values(r).join(' ').toLowerCase().includes(s)) return false;
    return true;
  });
}
function renderRawTable(){
  fRaw=getFilteredRaw();
  if(rSortCol) fRaw.sort((a,b)=>{let av=a[rSortCol],bv=b[rSortCol];if(['weekNum','sr','fasu','tasu','fdsr'].includes(rSortCol)){av=Number(av);bv=Number(bv);}return av<bv?-rSortDir:av>bv?rSortDir:0;});
  const tb=document.getElementById('raw-table-body');let h='';
  fRaw.forEach((r,i)=>{const ok=r.status==='Within Tolerance';h+=`<tr><td class="rn stick">${i+1}</td><td>${r.region}</td><td>${r.subregion}</td><td>${r.partner}</td><td>${r.location}</td><td>${r.queue}</td><td>${r.br}</td><td>${r.fy}</td><td>${r.quarter}</td><td>${r.month}</td><td>${r.week}</td><td>${r.sr.toLocaleString()}</td><td>${r.fasu.toLocaleString()}</td><td>${r.tasu.toLocaleString()}</td><td>${r.fdsr.toLocaleString()}</td><td>${r.lob}</td><td><span class="badge ${ok?'b-ok':'b-hi'}">${r.status}</span></td></tr>`;});
  tb.innerHTML=h;
  const rc=document.getElementById('raw-row-count');if(rc) rc.innerText=`${fRaw.length} of ${rawData.length} rows`;
  const dr=document.getElementById('dr-total-records');if(dr) dr.innerText=fRaw.length.toLocaleString();
}
function sortRawTable(col){const km={region:'region',subregion:'subregion',partner:'partner',location:'location',queue:'queue',busrep:'br',fy:'fy',quarter:'quarter',month:'month',week:'weekNum',sr:'sr',fasu:'fasu',tasu:'tasu',fdsr:'fdsr',lob:'lob'};const k=km[col]||col;if(rSortCol===k) rSortDir*=-1;else{rSortCol=k;rSortDir=1;}renderRawTable();}
