<script>
  const PRIMARY = new Set([
    'forecast_copilot/Dashboard — Forecast Copilot.html',
    'BPA_FORCASTING_MOCK.HTML',
    'ISG BPA — Business Planning and Analytics.html',
    'IBP_Forcasting.html',
    'enterprise_whatif_forecasting_platform.html',
    'bend_the_curve.html',
    'animated_UI.html',
  ]);

  const LABELS = {
    'forecast_copilot/Dashboard — Forecast Copilot.html': 'Forecast Copilot — AI Planning Suite',
    'BPA_FORCASTING_MOCK.HTML':                     'ISG BPA — Forecasting Suite (Active)',
    'ISG BPA — Business Planning and Analytics.html':                       'ISG BPA v2 — Redesign',
    'IBP_Forcasting.html':                          'ISG BPA: Business Planning and Analytics',
    'enterprise_whatif_forecasting_platform.html':  'What-If Simulation',
    'bend_the_curve.html':                          'Bend the Curve',
    'animated_UI.html':                             'Animated UI',
    'dell_workflow.html':                           'Dell Workflow',
    'simulation-overview-platform.html':            'Simulation Overview Platform',
    'executive_forecast_operational_dashboard.html':'Executive Forecast & Operational Dashboard',
    'epic_dashboard_mockup.html':                   'Epic Dashboard Mockup',
    'data.html':                                    'Data Management',
    'info_BPA.html':                                'ISG BPA — Info Version',
  };

  function iconFor(f) {
    f = f.toLowerCase();
    if (f.includes('animated')) return '✦';
    if (f.includes('ibp') || f.includes('forcasting') || f.includes('bpa')) return '◈';
    if (f.includes('whatif') || f.includes('enterprise')) return '◎';
    if (f.includes('bend') || f.includes('curve')) return '↗';
    if (f.includes('workflow')) return '⟳';
    if (f.includes('data')) return '⊞';
    if (f.includes('executive')) return '⬡';
    if (f.includes('climate')) return '◉';
    return '◻';
  }

  function buildLabel(file) {
    return LABELS[file] || file.replace(/\.html$/i,'').replace(/[_-]+/g,' ').replace(/\b\w/g, c=>c.toUpperCase());
  }

  function formatDT(iso) {
    try {
      return new Date(iso).toLocaleString(undefined,{
        year:'numeric',month:'short',day:'numeric',
        hour:'2-digit',minute:'2-digit',hour12:false
      });
    } catch { return iso || ''; }
  }

  function renderRows(pages, q) {
    const list = document.getElementById('pageList');
    const lq = (q||'').toLowerCase().trim();
    const ORDER = ['forecast_copilot/Dashboard — Forecast Copilot.html','BPA_FORCASTING_MOCK.HTML','ISG BPA — Business Planning and Analytics.html','IBP_Forcasting.html',
                   'enterprise_whatif_forecasting_platform.html','bend_the_curve.html','animated_UI.html'];
    const entries = Array.from(pages.entries())
      .filter(([,label]) => !lq || label.toLowerCase().includes(lq) || _[0]?.toLowerCase().includes(lq))
      .sort((a,b) => {
        const aP = PRIMARY.has(a[0]), bP = PRIMARY.has(b[0]);
        if (aP !== bP) return aP ? -1 : 1;
        const ai = ORDER.indexOf(a[0]), bi = ORDER.indexOf(b[0]);
        if (ai !== -1 && bi !== -1) return ai - bi;
        if (ai !== -1) return -1;
        if (bi !== -1) return 1;
        return a[1].localeCompare(b[1]);
      });

    list.innerHTML = '';
    if (!entries.length) {
      list.innerHTML = '<div class="empty">No modules match your search.</div>';
      return;
    }
    entries.forEach(([file, label]) => {
      const a = document.createElement('a');
      a.href = file; a.className = 'frow';
      const isP = PRIMARY.has(file);
      a.innerHTML = `
        <div class="ficon">${iconFor(file)}</div>
        <div class="finfo">
          <div class="fname">${label}</div>
          <div class="fpath">${file}</div>
        </div>
        ${isP ? '<span class="fbadge">Primary</span>' : ''}
        <span class="farrow">↗</span>`;
      list.appendChild(a);
    });
  }

  async function loadManifest() {
    try {
      const res = await fetch('manifest.json');
      if (!res.ok) throw new Error();
      const data = await res.json();

      const stamp = data.pagesPublishedAt ? `Last published: ${formatDT(data.pagesPublishedAt)}` : '';
      const sbEl = document.getElementById('sb-stamp');
      const hdrEl = document.getElementById('hdr-stamp');
      if (sbEl) sbEl.textContent = stamp;
      if (hdrEl) hdrEl.textContent = stamp;

      const pages = new Map();
      if (Array.isArray(data.mockups))
        data.mockups.forEach(m => { if (m.file && m.file !== 'index.html') pages.set(m.file, m.label || buildLabel(m.file)); });
      if (data.autoPages && typeof data.autoPages === 'object')
        Object.keys(data.autoPages).forEach(f => { if (f !== 'index.html' && !pages.has(f)) pages.set(f, buildLabel(f)); });

      renderRows(pages, '');
      document.getElementById('searchInput').addEventListener('input', e => renderRows(pages, e.target.value));
    } catch {
      document.getElementById('sb-stamp').textContent = '';
      document.getElementById('pageList').innerHTML = '<div class="empty">Unable to load file list.</div>';
    }
  }

  loadManifest();
</script>
